// ❌ This calls handleDelete('abc') immediately during render
<button onClick={handleDelete('abc')}>Delete</button>

// React receives undefined (the return value), not the function
// Clicking the button does nothing

function TodoList({ todos, onDelete, onToggle }) {
  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          <input
            type="checkbox"
            checked={todo.done}
            onChange={() => onToggle(todo.id)}       // closes over todo.id
          />
          {todo.text}
          <button onClick={() => onDelete(todo.id)}> // closes over todo.id
            Delete
          </button>
        </li>
      ))}
    </ul>
  );
}

function handleDelete(id, event) {
  event.stopPropagation(); // stop event from bubbling to a parent listener
  deleteItem(id);
}

// Pass both: arrow captures id, forwards the event
<button onClick={event => handleDelete(todo.id, event)}>Delete</button>

function TodoList({ todos, onDelete }) {
  // Single handler shared by all Delete buttons
  function handleDeleteClick(event) {
    const id = event.currentTarget.dataset.id;
    // dataset values are always strings — parse if your IDs are numbers
    onDelete(Number(id));
  }

  return (
    <ul>
      {todos.map(todo => (
        <li key={todo.id}>
          {todo.text}
          <button
            data-id={todo.id}
            onClick={handleDeleteClick}
          >
            Delete
          </button>
        </li>
      ))}
    </ul>
  );
}

// The factory: takes id, returns a handler function
const makeDeleter = (id) => () => deleteItem(id);

// Usage in JSX — calling makeDeleter(todo.id) returns a function
<button onClick={makeDeleter(todo.id)}>Delete</button>

// Equivalent arrow wrapper, just moved outside JSX
const handleToggle = (id) => (event) => {
  event.stopPropagation();
  toggleItem(id);
};

<input onChange={handleToggle(todo.id)} />

// Test the factory without rendering anything
test('makeDeleter calls deleteItem with the right id', () => {
  const deleteItem = jest.fn();
  const handler = makeDeleter(42, deleteItem);
  handler(); // simulate a click
  expect(deleteItem).toHaveBeenCalledWith(42);
});

// Parent holds the list and passes callbacks
function ShoppingCart() {
  const [items, setItems] = useState([
    { id: 1, name: 'Notebook', qty: 2 },
    { id: 2, name: 'Pen',      qty: 5 },
  ]);

  function handleRemove(id) {
    setItems(prev => prev.filter(item => item.id !== id));
  }

  function handleQtyChange(id, qty) {
    setItems(prev =>
      prev.map(item => item.id === id ? { ...item, qty } : item)
    );
  }

  return (
    <ul>
      {items.map(item => (
        <CartItem
          key={item.id}
          item={item}
          onRemove={() => handleRemove(item.id)}              // arrow captures item.id
          onQtyChange={qty => handleQtyChange(item.id, qty)} // arrow captures item.id, forwards qty
        />
      ))}
    </ul>
  );
}

// Child is simple — no closures, no data-*, just calls the prop
function CartItem({ item, onRemove, onQtyChange }) {
  return (
    <li>
      {item.name}
      <input
        type="number" value={item.qty} min="1"
        onChange={e => onQtyChange(Number(e.target.value))}
      />
      <button onClick={onRemove}>Remove</button>
    </li>
  );
}

// MemoRow only re-renders when its own props change
const MemoRow = React.memo(function Row({ item, onDelete }) {
  return (
    <tr>
      <td>{item.name}</td>
      <td><button onClick={onDelete}>Delete</button></td>
    </tr>
  );
});

function Table({ items, deleteItem }) {
  // Each row's handler is stable unless its own id changes
  // This is an optimization — only add it after profiling
  const makeDeleteHandler = useCallback(
    (id) => () => deleteItem(id),
    [deleteItem] // deleteItem must be stable too
  );

  return (
    <table>
      {items.map(item => (
        <MemoRow
          key={item.id}
          item={item}
          onDelete={makeDeleteHandler(item.id)}
        />
      ))}
    </table>
  );
}

function EmployeeTable({ employees }) {
  function handleView(id) {
    navigate(`/employees/${id}`);
  }

  function handleEdit(id) {
    setEditingId(id);
    setModalOpen(true);
  }

  function handleDelete(id, event) {
    event.stopPropagation(); // row has its own onClick for selection
    if (!confirm('Delete this employee?')) return;
    deleteEmployee(id);
  }

  return (
    <table>
      <tbody>
        {employees.map(emp => (
          <tr key={emp.id} onClick={() => handleView(emp.id)}> {/* row click: view */}
            <td>{emp.name}</td>
            <td>{emp.department}</td>
            <td>
              <button onClick={() => handleEdit(emp.id)}>Edit</button>
              <button onClick={event => handleDelete(emp.id, event)}>Delete</button>
            </td>
          </tr>
        ))}
      </tbody>
    </table>
  );
}

