<button onClick={handleDelete('abc')}>Delete</button>

// ✅ Arrow runs handleDelete('abc') on click
<button onClick={() => handleDelete('abc')}>Delete</button>

// ❌ Compares string '42' to number 42 — never matches
function handleDelete(e) {
  const id = e.currentTarget.dataset.id; // '42' (string)
  deleteItem(id); // deleteItem expects a number
}

// ✅ Parse immediately
function handleDelete(e) {
  const id = Number(e.currentTarget.dataset.id); // 42 (number)
  deleteItem(id);
}

// Button with an icon inside
<button data-id="42" onClick={handleDelete}>
  <TrashIcon /> {/* clicking this makes event.target the <svg>, not the <button> */}
</button>

// ❌ May fail if user clicks the icon
