import { render, screen, fireEvent } from '@testing-library/react';
import TodoList from './TodoList';

test('calls onDelete with the correct todo id', () => {
  const onDelete = jest.fn();
  const todos = [
    { id: 10, text: 'Buy milk', done: false },
    { id: 11, text: 'Read book', done: false },
  ];

  render(<TodoList todos={todos} onDelete={onDelete} onToggle={jest.fn()} />);

  // Click the Delete button for the second todo
  const deleteButtons = screen.getAllByRole('button', { name: 'Delete' });
  fireEvent.click(deleteButtons[1]);

  expect(onDelete).toHaveBeenCalledTimes(1);
  expect(onDelete).toHaveBeenCalledWith(11); // second todo's id
});

// Handler that needs both the field name and the new value
function handleFieldUpdate(field, value) {
  setProfile(prev => ({ ...prev, [field]: value }));
}

function ProfileForm() {
  const [profile, setProfile] = useState({ name: '', bio: '', website: '' });

  function handleFieldUpdate(field, value) {
    setProfile(prev => ({ ...prev, [field]: value }));
  }

  return (
    <form>
      <input
        value={profile.name}
        onChange={e => handleFieldUpdate('name', e.target.value)}
        placeholder="Name"
      />
      <textarea
        value={profile.bio}
        onChange={e => handleFieldUpdate('bio', e.target.value)}
        placeholder="Bio"
      />
      <input
        value={profile.website}
        onChange={e => handleFieldUpdate('website', e.target.value)}
        placeholder="Website"
      />
    </form>
  );
}

function InvoiceEditor() {
  const [lines, setLines] = useState([
    { id: 1, description: '', qty: 1, unitPrice: 0 },
  ]);

  function addLine() {
    const newId = lines.length > 0 ? Math.max(...lines.map(l => l.id)) + 1 : 1;
    setLines(prev => [...prev, { id: newId, description: '', qty: 1, unitPrice: 0 }]);
  }

  function removeLine(id) {
    setLines(prev => prev.filter(l => l.id !== id));
  }

  function updateLine(id, field, value) {
    setLines(prev =>
      prev.map(l => l.id === id ? { ...l, [field]: value } : l)
    );
  }

  const total = lines.reduce((sum, l) => sum + l.qty * l.unitPrice, 0);

  return (
    <div>
      <table>
        <tbody>
          {lines.map(line => (
            <tr key={line.id}>
              <td>
                <input
                  value={line.description}
                  onChange={e => updateLine(line.id, 'description', e.target.value)}
                  placeholder="Description"
                />
              </td>
              <td>
                <input
                  type="number" value={line.qty} min="1"
                  onChange={e => updateLine(line.id, 'qty', Number(e.target.value))}
                />
              </td>
              <td>
                <input
                  type="number" value={line.unitPrice} min="0" step="0.01"
                  onChange={e => updateLine(line.id, 'unitPrice', Number(e.target.value))}
                />
              </td>
              <td>${(line.qty * line.unitPrice).toFixed(2)}</td>
              <td>
                <button onClick={() => removeLine(line.id)}>Remove</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <button onClick={addLine}>Add Line</button>
      <p>Total: ${total.toFixed(2)}</p>
    </div>
  );
}

// ❌ BAD: exposes the raw DOM event — caller must dig into it
function ColorPicker({ onChange }) {
  return (
    <div>
      {['red', 'green', 'blue'].map(color => (
        <button key={color} onClick={onChange}>{color}</button>
        // caller receives a SyntheticEvent and must read event.target.textContent
      ))}
    </div>
  );
}

// ✅ GOOD: callback receives the selected color directly
function ColorPicker({ onSelect }) {
  return (
    <div>
      {['red', 'green', 'blue'].map(color => (
        <button key={color} onClick={() => onSelect(color)}>{color}</button>
      ))}
    </div>
  );
}

// Caller is clean:
<ColorPicker onSelect={color => setTheme(color)} />

// ❌ BAD: one handler per item — does not scale
function ItemList() {
  function handleDeleteItem1() { deleteItem(1); }
  function handleDeleteItem2() { deleteItem(2); }
  function handleDeleteItem3() { deleteItem(3); }

  return (
    <ul>
      <li><button onClick={handleDeleteItem1}>Delete 1</button></li>
      <li><button onClick={handleDeleteItem2}>Delete 2</button></li>
      <li><button onClick={handleDeleteItem3}>Delete 3</button></li>
    </ul>
  );
}

// ✅ GOOD: one handler, argument passed via arrow wrapper
function ItemList({ items }) {
  function handleDelete(id) { deleteItem(id); }

  return (
    <ul>
      {items.map(item => (
        <li key={item.id}>
          <button onClick={() => handleDelete(item.id)}>Delete</button>
        </li>
      ))}
    </ul>
  );
}
